/*
 * OCR A GCSE Physics (J249) — Exam Practice Question Bank
 * 40 written exam-style questions per topic, varying from 1-mark recall to 6-mark extended.
 * Each question has a modelAnswer/markScheme and supports requiresDiagram: true for questions
 * where the student is expected to draw a diagram as part of the answer.
 */

const PHYSICS_OCR_A_GCSE_PRACTICE = {

  /* ═════════════════════════════════════════════════════════ P1 Matter */
  'P1': {
    name: 'Matter',
    questions: [
      { q: 'State what is meant by density.', marks: 1, markScheme: `• Mass per unit volume of a substance (1)` },
      { q: 'Give the SI unit of density and one alternative unit.', marks: 2, markScheme: `• kg/m³ (1)\n• g/cm³ is also commonly used (1 g/cm³ = 1000 kg/m³) (1)` },
      { q: 'State the equation for pressure in a solid with each symbol named.', marks: 2, markScheme: `• p = F/A (1)\n• p = pressure (Pa), F = force (N), A = area (m²) (1)` },
      { q: 'Describe how you would measure the density of a regular solid (e.g. a metal cube).', marks: 3, markScheme: `• Measure the mass m using a top-pan balance (1)\n• Measure the sides with a ruler/vernier and calculate V = l × w × h (1)\n• Density ρ = m / V (1)` },
      { q: 'A block of aluminium has mass 54 g and volume 20 cm³. Calculate its density in g/cm³ and state it in kg/m³.', marks: 2, markScheme: `• ρ = 54/20 = 2.7 g/cm³ (1)\n• = 2 700 kg/m³ (1)` },
      { q: 'Describe, with the help of a labelled diagram, how to measure the density of an irregular solid using displacement.', marks: 5, requiresDiagram: true, markScheme: `• Labelled diagram showing eureka can, measuring cylinder under spout, object ready to be lowered in (1)\n• Weigh object on a balance, record mass m (1)\n• Fill eureka can to spout level (1)\n• Lower object gently; catch displaced water in measuring cylinder (1)\n• V = displaced water volume; ρ = m/V (1)` },
      { q: 'Compare the particle arrangement and movement in a solid, liquid and gas.', marks: 6, markScheme: `• Solid: particles regular, touching, strong forces, vibrate in fixed positions (2)\n• Liquid: particles random but still close, slide past each other, weaker forces (2)\n• Gas: particles random, far apart, negligible forces, fast random motion (2)` },
      { q: 'Draw and label a heating curve showing temperature against energy added for a substance going from solid to gas. Explain why there are two plateaus.', marks: 5, requiresDiagram: true, markScheme: `• Diagram: T vs energy with a rising line, flat plateau at T_m, another rising line, plateau at T_b, final rise (2)\n• Plateaus correspond to melting and boiling (1)\n• Energy is used to break bonds / overcome intermolecular forces (1)\n• Temperature constant during a change of state — kinetic energy unchanged (1)` },
      { q: 'State what is meant by internal energy of a substance.', marks: 2, markScheme: `• Total energy stored by the particles of a substance (1)\n• Sum of kinetic energies (motion) and potential energies (bonds) of the particles (1)` },
      { q: 'Explain why a change of state is a physical change.', marks: 2, markScheme: `• The chemical composition is unchanged (1)\n• It is reversible and mass is conserved (1)` },
      { q: 'State the equation relating energy, mass, specific heat capacity and temperature change.', marks: 1, markScheme: `• ΔE = m × c × Δθ (1)` },
      { q: 'A 2.5 kg block of copper (c = 385 J/kg °C) is heated from 20 °C to 120 °C. Calculate the energy supplied.', marks: 3, markScheme: `• ΔE = m × c × Δθ (1)\n• = 2.5 × 385 × (120 − 20) = 2.5 × 385 × 100 (1)\n• = 96 250 J ≈ 96.3 kJ (1)` },
      { q: 'Explain why water has a high specific heat capacity and describe ONE practical use of this.', marks: 3, markScheme: `• Strong hydrogen bonds between molecules need much energy to increase particle KE (1)\n• Hence a large energy input for a small ΔT (1)\n• Used as a coolant in car radiators / central heating systems / industrial machines — absorbs lots of heat without excessive temperature rise (1)` },
      { q: 'State what is meant by specific latent heat of fusion.', marks: 2, markScheme: `• Energy needed to change the state of 1 kg of substance (from solid to liquid) without a temperature change (1)\n• Unit: J/kg (1)` },
      { q: 'Calculate the energy needed to melt 400 g of ice at 0 °C. (L = 334 000 J/kg)', marks: 3, markScheme: `• Convert mass: 0.400 kg (1)\n• E = m × L = 0.400 × 334 000 (1)\n• = 133 600 J ≈ 134 kJ (1)` },
      { q: 'Calculate the total energy needed to warm 0.20 kg of ice at −10 °C to water at 30 °C. (c_ice = 2 100, L = 334 000, c_water = 4 200 — all J/kg °C or J/kg.)', marks: 5, markScheme: `• Warm ice: 0.20 × 2 100 × 10 = 4 200 J (1)\n• Melt ice: 0.20 × 334 000 = 66 800 J (1)\n• Warm water: 0.20 × 4 200 × 30 = 25 200 J (1)\n• Total 4 200 + 66 800 + 25 200 (1)\n• = 96 200 J (1)` },
      { q: 'State and explain the equation for gas pressure and volume at constant temperature.', marks: 3, markScheme: `• p₁V₁ = p₂V₂ / pV = constant (1)\n• At constant T, compressing a gas reduces V so p increases (1)\n• Because particles hit walls more often per second (1)` },
      { q: '20 L of gas at 300 kPa is compressed at constant T to 5 L. Find the new pressure.', marks: 2, markScheme: `• p₁V₁ = p₂V₂ → 300 × 20 = p₂ × 5 (1)\n• p₂ = 6 000/5 = 1 200 kPa (1.2 MPa) (1)` },
      { q: 'Explain, in terms of particles, why a gas exerts pressure on the walls of its container.', marks: 4, markScheme: `• Gas particles move randomly at high speed (1)\n• They collide with the walls (1)\n• Each collision exerts a small force during the momentum change (1)\n• Total force per unit area of wall = pressure (1)` },
      { q: 'Explain in terms of particles why gas pressure increases when temperature increases (constant volume).', marks: 4, markScheme: `• Higher T → particles have greater kinetic energy (1)\n• They move faster (1)\n• So they hit the walls more often AND with greater force (1)\n• Hence increased pressure per unit area (1)` },
      { q: 'Give the equation for pressure in a liquid at depth h and explain why dams are thicker at the base.', marks: 4, markScheme: `• p = h × ρ × g (1)\n• At greater depth, more liquid above, so larger pressure (1)\n• The horizontal force per unit area on the wall is greater at the base (1)\n• Thicker base wall can withstand the larger force (1)` },
      { q: 'Calculate the pressure at the bottom of a swimming pool 2.5 m deep (ρ = 1 000 kg/m³, g = 9.8).', marks: 2, markScheme: `• p = h × ρ × g = 2.5 × 1000 × 9.8 (1)\n• = 24 500 Pa (= 24.5 kPa due to water) (1)` },
      { q: 'Explain why atmospheric pressure decreases with altitude.', marks: 3, markScheme: `• The atmosphere has weight pressing downwards (1)\n• At higher altitude, there is less air above (1)\n• Less mass of air → less force per unit area → lower atmospheric pressure (1)` },
      { q: 'Explain what upthrust is and why a steel ship can float.', marks: 4, markScheme: `• Upthrust is the net upward force on a submerged object due to pressure increasing with depth (1)\n• Equal to the weight of the fluid displaced (Archimedes) (1)\n• A ship\'s hull displaces a large volume of water (1)\n• The weight of displaced water exceeds the ship\'s weight → ship floats (1)` },
      { q: 'State what is meant by sublimation, giving an example.', marks: 2, markScheme: `• Change from solid directly to gas without passing through liquid (1)\n• Example: dry ice (solid CO₂), frost vaporising from grass (1)` },
      { q: 'Draw and label the arrangement of particles in a gas. Explain why gases have low density.', marks: 4, requiresDiagram: true, markScheme: `• Diagram with small circles spread far apart, random positions, arrows showing rapid random motion (2)\n• Particles are widely separated in a gas (1)\n• Mass per unit volume is therefore small — low density (1)` },
      { q: 'A material has density 800 kg/m³. A sample has mass 240 g. Calculate its volume in cm³.', marks: 3, markScheme: `• 800 kg/m³ = 0.8 g/cm³ (1)\n• V = m/ρ = 240 / 0.8 (1)\n• = 300 cm³ (1)` },
      { q: 'Explain why ice takes up more volume than the same mass of liquid water.', marks: 3, markScheme: `• When water freezes, molecules form a regular open lattice held by hydrogen bonds (1)\n• This arrangement occupies more space than the liquid (1)\n• Therefore ice has a lower density than water (ice floats) (1)` },
      { q: 'Sketch a graph of pressure against volume for a gas at constant temperature. State the relationship shown.', marks: 3, requiresDiagram: true, markScheme: `• Curve starts high on left and falls steeply towards the x-axis as V increases (rectangular hyperbola) (2)\n• pV = constant → pressure inversely proportional to volume (1)` },
      { q: 'Describe how you would measure the density of a sample of cooking oil.', marks: 4, markScheme: `• Place an empty measuring cylinder on balance and tare to zero (1)\n• Pour in a known volume of oil, e.g. 50 cm³ (1)\n• Record new mass of oil (1)\n• Density ρ = m/V (1)` },
      { q: 'Explain how a hydraulic system (e.g. car brakes) uses liquid pressure to transmit force.', marks: 4, markScheme: `• Liquids are incompressible and pressure is transmitted equally in all directions (1)\n• A small force on a small piston creates a pressure p = F/A (1)\n• Same pressure acts on a larger piston, giving F = p × A_larger, a larger output force (1)\n• Ratio of output to input forces = ratio of piston areas (1)` },
      { q: 'Why is it unsafe to leave aerosol cans in hot sunlight?', marks: 3, markScheme: `• Higher temperature → gas particles move faster (1)\n• Increased pressure inside the can as collisions with walls occur more frequently / forcefully (1)\n• If pressure exceeds can strength, the can may burst / explode (1)` },
      { q: 'Show that a 120 kPa gas sample of volume 2.0 m³ becomes 600 kPa when compressed to 0.4 m³ (constant T).', marks: 3, markScheme: `• p₁V₁ = 120 × 2.0 = 240 kPa m³ (1)\n• p₂ = 240 / 0.4 (1)\n• = 600 kPa ✓ (1)` },
      { q: 'A 0.5 kg piece of copper at 150 °C is placed in 0.8 kg of water at 20 °C. Assuming no losses to surroundings, find the final temperature. (c_Cu = 385, c_w = 4 200)', marks: 5, markScheme: `• Heat lost by copper = heat gained by water (1)\n• 0.5 × 385 × (150 − T) = 0.8 × 4 200 × (T − 20) (1)\n• 192.5 × (150 − T) = 3 360 × (T − 20) (1)\n• 28 875 − 192.5T = 3 360T − 67 200 → 96 075 = 3 552.5T (1)\n• T ≈ 27 °C (accept 27 ± 1) (1)` },
      { q: 'Explain why heating a substance at the same power does not always cause the same rise in temperature.', marks: 3, markScheme: `• Depends on mass and specific heat capacity (ΔE = mcΔθ) (1)\n• Some energy may be lost to surroundings (1)\n• During a change of state no temperature rise occurs — energy is used to break bonds (1)` },
      { q: 'State one strength and one limitation of using the particle model to explain matter.', marks: 2, markScheme: `• Strength: predicts many observations (gas pressure, changes of state, density differences) (1)\n• Limitation: simplified — ignores quantum behaviour, internal structure of particles, real intermolecular forces (1)` },
      { q: 'A block of wood (mass 0.30 kg) floats in water. Explain why, in terms of density and upthrust.', marks: 3, markScheme: `• Wood has a lower density than water (1)\n• When partially submerged, the weight of water displaced equals the weight of wood (upthrust balances weight) (1)\n• So the block floats in equilibrium (1)` },
      { q: 'Explain why the density of a gas changes more rapidly with temperature than the density of a solid.', marks: 3, markScheme: `• Heating a gas causes a large volume change (huge gaps between particles are sensitive to T) (1)\n• ρ = m/V, so V changes → ρ changes (1)\n• Solid particles cannot move far so volume barely changes — density nearly constant (1)` },
      { q: 'A student has a sample of material and a balance, ruler, measuring cylinder. Explain, step by step, how they could tell whether the material is solid gold (ρ = 19 300 kg/m³) or fool\'s gold (pyrite, ρ ≈ 5 000 kg/m³).', marks: 5, markScheme: `• Weigh the sample on balance — record m (1)\n• Determine volume by displacement if irregular or ruler measurements if regular (1)\n• Calculate ρ = m / V (1)\n• Compare to 19 300 kg/m³ vs 5 000 kg/m³ (1)\n• Take repeated readings and mean to reduce error, and compare with the stated densities to identify the material (1)` },
      { q: 'A gas sample is heated from 20 °C to 100 °C at CONSTANT PRESSURE. Describe what happens to its volume and explain.', marks: 3, markScheme: `• Volume increases (1)\n• Particles move faster and push the container/piston outwards (1)\n• To keep p constant, V must increase as T rises (Charles\' law) (1)` },
      { q: '"All objects experience the same gravitational acceleration in a vacuum, regardless of mass." Explain why this does NOT contradict F = ma.', marks: 4, markScheme: `• Gravitational force F = m × g — increases with mass (1)\n• Newton\'s 2nd law: a = F/m (1)\n• Substituting: a = mg/m = g (1)\n• So acceleration is independent of m — cancels out. F = ma still holds; a happens to equal g (1)` },
    ]
  },

  /* ═════════════════════════════════════════════════════════ P2 Forces */
  'P2': {
    name: 'Forces',
    questions: [
      { q: 'State one scalar and one vector quantity, with a clear reason for each.', marks: 2, markScheme: `• Scalar e.g. mass (size only — no direction) (1)\n• Vector e.g. velocity/force/displacement (has size and direction) (1)` },
      { q: 'State the equation relating weight, mass and gravitational field strength.', marks: 1, markScheme: `• W = m × g (1)` },
      { q: 'Compare mass and weight.', marks: 3, markScheme: `• Mass: measure of matter, scalar, kg, constant anywhere (1)\n• Weight: force due to gravity, vector, N (1)\n• Weight changes with g (e.g. much smaller on Moon); mass does not (1)` },
      { q: 'Distinguish between contact and non-contact forces, giving one example of each.', marks: 3, markScheme: `• Contact forces require objects to be touching (e.g. friction, tension, normal) (1.5)\n• Non-contact forces act through a field, no touching needed (e.g. gravity, magnetic, electrostatic) (1.5)` },
      { q: 'Calculate the weight of a 55 kg person on Earth (g = 9.8) and on the Moon (g = 1.6).', marks: 2, markScheme: `• Earth: W = 55 × 9.8 = 539 N (1)\n• Moon: W = 55 × 1.6 = 88 N (1)` },
      { q: 'A 200 N force acts east and a 120 N force acts west. Calculate the resultant force.', marks: 2, markScheme: `• Resultant = 200 − 120 (1)\n• = 80 N east (1)` },
      { q: 'Draw a free-body diagram of a car moving at constant velocity on a straight road. Label and explain why forces are balanced.', marks: 4, requiresDiagram: true, markScheme: `• Clear diagram with: weight down, normal contact up, driving force forward, friction/air resistance backward (2)\n• Horizontal forces balanced → no horizontal resultant (1)\n• Constant velocity → Newton\'s 1st law (balanced forces) (1)` },
      { q: 'State Newton\'s First Law.', marks: 2, markScheme: `• Object stays at rest or moves at constant velocity (1)\n• Unless a resultant (unbalanced) force acts on it (1)` },
      { q: 'State Newton\'s Second Law in equation form with units.', marks: 2, markScheme: `• F = m × a (1)\n• F in N, m in kg, a in m/s² (1)` },
      { q: 'A 1 500 kg car accelerates at 2.5 m/s². Calculate the net force on it.', marks: 2, markScheme: `• F = m × a = 1 500 × 2.5 (1)\n• = 3 750 N (1)` },
      { q: 'State Newton\'s Third Law. Give an example clearly showing both forces.', marks: 3, markScheme: `• When two objects interact, they exert equal and opposite forces on each other (2)\n• Example: rocket pushes exhaust gas down, gas pushes rocket up with equal force (or: you push on wall, wall pushes on you) (1)` },
      { q: 'Explain why a passenger lurches forward when a car brakes suddenly, using Newton\'s laws.', marks: 3, markScheme: `• Passenger has inertia — tendency to continue their current state of motion (Newton\'s 1st law) (1)\n• Car decelerates due to braking force on car (1)\n• Passenger continues forward until an external force (seatbelt) slows them (1)` },
      { q: 'A trolley accelerates from rest at 3 m/s² for 4 s. Find (i) final velocity, (ii) distance travelled.', marks: 3, markScheme: `• v = u + at = 0 + 3 × 4 = 12 m/s (1)\n• s = ½(u+v)t = ½ × 12 × 4 (1) = 24 m (1)` },
      { q: 'A car accelerates uniformly from 10 m/s over 60 m using v² = u² + 2as with a = 1.5 m/s². Find v.', marks: 3, markScheme: `• v² = 10² + 2 × 1.5 × 60 (1)\n• = 100 + 180 = 280 (1)\n• v = √280 = 16.7 m/s (1)` },
      { q: 'Sketch a distance-time graph showing: stationary, constant speed, acceleration. Label each section.', marks: 4, requiresDiagram: true, markScheme: `• Horizontal segment labelled "stationary" (1)\n• Straight inclined segment labelled "constant speed" (1)\n• Curve getting steeper labelled "accelerating" (1)\n• Axes labelled: d vs t (1)` },
      { q: 'Sketch a velocity-time graph for a car that accelerates uniformly, moves at constant speed, then decelerates to rest. State what the area under the graph represents.', marks: 4, requiresDiagram: true, markScheme: `• Increasing straight line (accel), horizontal (constant v), decreasing straight line to 0 (decel) (2)\n• Axes labelled (1)\n• Area under graph = distance travelled (1)` },
      { q: 'State the equation for work done and explain its unit.', marks: 2, markScheme: `• W = F × d (1)\n• 1 joule = 1 newton × 1 metre (1)` },
      { q: 'A horse pulls a cart with 450 N of force for 30 m. Calculate the work done.', marks: 2, markScheme: `• W = F × d = 450 × 30 (1)\n• = 13 500 J = 13.5 kJ (1)` },
      { q: 'Define stopping distance and its two components.', marks: 2, markScheme: `• Stopping distance = thinking distance + braking distance (1)\n• Thinking = distance travelled during reaction; Braking = distance while decelerating to stop (1)` },
      { q: 'State three factors that affect thinking distance and three that affect braking distance.', marks: 6, markScheme: `Thinking (any 3 for 3 marks): reaction time, alcohol/drugs, tiredness, distractions (phone), speed of vehicle (3)\nBraking (any 3 for 3 marks): speed (v²), road surface (wet/icy), tyre condition, brake condition, mass of vehicle (3)` },
      { q: 'Explain why high-speed braking is much more dangerous than low-speed braking.', marks: 4, markScheme: `• Braking distance ∝ v² (1)\n• Doubling speed quadruples braking distance (1)\n• Kinetic energy ∝ v² so brakes must do much more work — more heat produced (1)\n• Risk of brake fade (overheating) and loss of control (1)` },
      { q: 'State the equation for momentum and its SI unit.', marks: 2, markScheme: `• p = m × v (1)\n• kg m/s (1)` },
      { q: 'State the law of conservation of momentum.', marks: 2, markScheme: `• Total momentum of a closed system before an event = total momentum after (1)\n• Provided no external forces act (1)` },
      { q: 'A 2 kg ball travels at 6 m/s east and collides with a stationary 3 kg ball. They stick and move east together. Find their common velocity.', marks: 3, markScheme: `• Total p = 2 × 6 + 3 × 0 = 12 kg m/s (1)\n• Combined mass = 5 kg (1)\n• v = 12/5 = 2.4 m/s east (1)` },
      { q: 'Explain how an airbag reduces the force on a driver during a collision.', marks: 4, markScheme: `• Momentum change Δp = m × Δv is fixed (1)\n• Airbag increases collision time (1)\n• F = Δp/t, so larger t → smaller F (1)\n• Smaller force → less injury to the driver (1)` },
      { q: 'A 0.4 kg ball moving at 5 m/s is caught by a player who brings it to rest in 0.2 s. Calculate average force.', marks: 3, markScheme: `• Δp = 0.4 × 5 = 2 kg m/s (1)\n• F = Δp/t = 2 / 0.2 (1)\n• = 10 N (1)` },
      { q: 'Describe three car safety features that exploit the principle of increasing collision time.', marks: 3, markScheme: `• Crumple zones — crush to extend collision time (1)\n• Seatbelts — stretch slightly to slow driver over longer time (1)\n• Airbag — inflates between driver and dashboard to spread the force out over time/area (1)` },
      { q: 'State the equation for the moment of a force.', marks: 1, markScheme: `• Moment M = F × d (perpendicular distance) (1)` },
      { q: 'A 50 N force acts on a 0.6 m spanner perpendicular to it. Calculate the moment.', marks: 2, markScheme: `• M = F × d = 50 × 0.6 (1)\n• = 30 N m (1)` },
      { q: 'State the principle of moments.', marks: 2, markScheme: `• For a balanced object: total clockwise moment = total anticlockwise moment about the pivot (1)\n• No net turning effect (1)` },
      { q: 'A seesaw has a 300 N child at 1.5 m on one side. How far from the pivot must a 450 N child sit on the other side for balance?', marks: 3, markScheme: `• Anticlockwise moment = 300 × 1.5 = 450 N m (1)\n• For balance: 450 × d = 450 (1)\n• d = 1.0 m (1)` },
      { q: 'Explain how gears are used as force multipliers.', marks: 3, markScheme: `• Small driver gear meshing with larger driven gear (1)\n• Applied torque on driver produces a bigger torque on driven gear (1)\n• But driven gear rotates more slowly — trade-off between force and speed (1)` },
      { q: 'Explain why the elastic limit is important when using Hooke\'s law.', marks: 3, markScheme: `• Hooke\'s law (F = k e) is valid only up to the limit of proportionality (1)\n• Beyond this the spring is permanently deformed (plastic deformation) (1)\n• Force-extension graph becomes curved / non-linear (1)` },
      { q: 'Sketch a typical force-extension graph for a spring and label the limit of proportionality.', marks: 3, requiresDiagram: true, markScheme: `• Straight line through origin at first (linear region) (1)\n• Curves off after the limit of proportionality (1)\n• LoP labelled clearly (1)` },
      { q: 'A spring has a spring constant of 40 N/m. It is stretched by 0.15 m. Calculate (i) applied force, (ii) energy stored.', marks: 3, markScheme: `• F = k × e = 40 × 0.15 = 6 N (1)\n• E = ½ × k × e² = ½ × 40 × 0.15² (1)\n• = 0.45 J (1)` },
      { q: 'State one similarity and one difference between static and kinetic friction.', marks: 2, markScheme: `• Both oppose relative motion between surfaces in contact (1)\n• Static friction exists before motion starts and is usually greater than kinetic friction (once moving) (1)` },
      { q: 'A 70 kg skydiver falls from a plane. Describe how the forces change until terminal velocity is reached.', marks: 5, markScheme: `• Initially weight > air resistance → net downward force → accelerates (1)\n• As speed increases, air resistance increases (1)\n• When air resistance = weight, net force = 0 (1)\n• Acceleration = 0, constant velocity (terminal velocity) (1)\n• After parachute opens, air resistance greatly increases, skydiver decelerates, reaches a new, lower terminal velocity (1)` },
      { q: 'A 1 200 kg car brakes from 30 m/s to rest in 6 s. Calculate (i) deceleration, (ii) braking force.', marks: 3, markScheme: `• a = (0 − 30)/6 = −5 m/s² (1)\n• F = m × a = 1 200 × 5 = 6 000 N (decelerating) (2)` },
      { q: 'Discuss, using F = Δp/t, why cycle helmets and crash mats work on the same physical principle.', marks: 6, markScheme: `• Δp = m × Δv (the change in momentum to stop the person) is fixed (1)\n• Helmets and crash mats compress on impact, extending the stopping time t (1)\n• F = Δp / t, so a larger t produces a smaller F (1)\n• Smaller force on head/body reduces injury (1)\n• Both also spread force over a larger area → smaller pressure (1)\n• So the principle is identical: extend time and spread area to reduce force/pressure (1)` },
      { q: 'A force-time graph for an impact shows a peak force of 4 kN for 0.02 s. Estimate the change in momentum (area under graph, assume triangle).', marks: 3, markScheme: `• Area = ½ × base × height (1)\n• = ½ × 0.02 × 4 000 (1)\n• = 40 N s = 40 kg m/s (1)` },
    ]
  },

  /* ═════════════════════════════════════════════════════════ P3 Electricity and Magnetism */
  'P3': {
    name: 'Electricity and Magnetism',
    questions: [
      { q: 'State what is meant by electric current.', marks: 2, markScheme: `• Flow of electric charge (1)\n• In a metal wire, charge carriers are free electrons; 1 A = 1 C/s (1)` },
      { q: 'Write the equation Q = I × t and name each quantity with units.', marks: 2, markScheme: `• Q = charge (C), I = current (A), t = time (s) (1)\n• 1 C = 1 A × 1 s (1)` },
      { q: 'State where an ammeter and a voltmeter should be placed in a circuit.', marks: 2, markScheme: `• Ammeter in series with the component (1)\n• Voltmeter in parallel across the component (1)` },
      { q: 'State Ohm\'s law and the conditions under which it applies.', marks: 3, markScheme: `• V = I × R (1)\n• The current is directly proportional to the potential difference across the conductor (1)\n• At constant temperature (for an ohmic conductor) (1)` },
      { q: 'Calculate the resistance of a component where 0.4 A flows with 6 V applied.', marks: 2, markScheme: `• R = V / I = 6 / 0.4 (1)\n• = 15 Ω (1)` },
      { q: 'Draw a circuit diagram for a cell, switch, resistor and ammeter in series, with a voltmeter across the resistor.', marks: 4, requiresDiagram: true, markScheme: `• Correct symbols for cell, switch, resistor, ammeter, voltmeter (2)\n• Ammeter in series loop (1)\n• Voltmeter in parallel across resistor (1)` },
      { q: 'Sketch and describe the I-V characteristic of a fixed ohmic resistor at constant T.', marks: 3, requiresDiagram: true, markScheme: `• Straight line through origin, positive gradient, symmetrical in ±V (2)\n• Constant gradient → constant resistance (ohmic) (1)` },
      { q: 'Sketch and explain the I-V characteristic of a filament lamp.', marks: 4, requiresDiagram: true, markScheme: `• S-shape/curve through origin, flatter at extremes (2)\n• Current increases more slowly at high pd because filament heats up (1)\n• Higher T → higher resistance → less current per extra volt (1)` },
      { q: 'Sketch and explain the I-V characteristic of a diode.', marks: 3, requiresDiagram: true, markScheme: `• Zero current for negative V; rapid rise in current beyond a small forward threshold pd (~0.6 V) (2)\n• Only conducts in one direction when forward-biased above threshold (1)` },
      { q: 'Explain the behaviour of an LDR and give one practical application.', marks: 3, markScheme: `• Resistance decreases as light intensity increases (1)\n• Because more photons create more free charge carriers in the semiconductor (1)\n• Used in automatic street lighting / camera light meters (1)` },
      { q: 'Explain the behaviour of a NTC thermistor and give one practical application.', marks: 3, markScheme: `• Resistance decreases as temperature increases (1)\n• Because warmer carriers are more easily freed from atoms in semiconductor (1)\n• Used in thermostats / temperature sensors / car engine temperature monitors (1)` },
      { q: 'Two 6 Ω resistors are connected (i) in series, (ii) in parallel. Calculate the total resistance in each case.', marks: 3, markScheme: `• Series: R = 6 + 6 = 12 Ω (1)\n• Parallel: 1/R = 1/6 + 1/6 = 2/6 (1)\n• R = 3 Ω (1)` },
      { q: 'State three properties of a series circuit.', marks: 3, markScheme: `• Current is the same everywhere (1)\n• pd adds up: V_total = V₁ + V₂ + ... (1)\n• Total resistance = sum of resistances (1)` },
      { q: 'State three properties of a parallel circuit.', marks: 3, markScheme: `• pd across each branch is the same (= source pd) (1)\n• Total current = sum of branch currents (1)\n• Total resistance less than the smallest branch resistance (1)` },
      { q: 'Explain why household lighting is wired in parallel.', marks: 3, markScheme: `• Each light gets the full 230 V regardless of others (1)\n• If one bulb breaks, the others still work (1)\n• Each can be controlled independently by its own switch (1)` },
      { q: 'State the colours of the live, neutral and earth wires in a UK three-pin plug.', marks: 3, markScheme: `• Live: brown (1)\n• Neutral: blue (1)\n• Earth: green and yellow stripes (1)` },
      { q: 'Explain the function of a fuse in a three-pin plug.', marks: 3, markScheme: `• In the live wire (1)\n• Melts if current exceeds its rating (1)\n• Breaks circuit to protect user and prevent fire in a fault (1)` },
      { q: 'Explain how the earth wire and fuse together prevent electric shocks from a fault.', marks: 4, markScheme: `• If live touches metal casing, casing becomes live — dangerous (1)\n• Earth wire provides a low-resistance path to ground (1)\n• A large fault current flows → fuse melts (1)\n• Live connection broken, appliance safe to touch (1)` },
      { q: 'State the equation for electrical power in two forms.', marks: 2, markScheme: `• P = V × I (1)\n• P = I² × R (or P = V²/R) (1)` },
      { q: 'A hair dryer uses 2 000 W at 230 V. Calculate (i) current, (ii) correct fuse choice.', marks: 3, markScheme: `• I = P/V = 2 000 / 230 ≈ 8.7 A (1)\n• Needs a fuse above 8.7 A (2)\n• 13 A fuse is the correct choice (1)` },
      { q: 'Write the equation E = Q × V and describe what it means physically.', marks: 2, markScheme: `• E = charge × potential difference (1)\n• Energy transferred by a charge equals its pd × quantity of charge (1)` },
      { q: 'Explain how mains electricity differs from battery electricity (ac vs dc).', marks: 3, markScheme: `• Batteries give direct current (one direction) (1)\n• UK mains is alternating current — reverses direction (1)\n• Mains is 230 V at 50 Hz (1)` },
      { q: 'State the purpose of a transformer and explain why it only works with AC.', marks: 4, markScheme: `• Transformer changes the voltage of ac supply (1)\n• Two coils on an iron core (1)\n• AC in primary creates changing magnetic field (1)\n• Changing flux induces AC pd in secondary; DC gives steady flux → no induction → no output (1)` },
      { q: 'Write the transformer voltage ratio equation. State what "step-up" and "step-down" mean.', marks: 3, markScheme: `• V_p / V_s = N_p / N_s (1)\n• Step-up: V_s > V_p (more turns on secondary) (1)\n• Step-down: V_s < V_p (fewer turns on secondary) (1)` },
      { q: 'A transformer has 500 turns primary, 100 secondary, 230 V ac input. Find output voltage.', marks: 2, markScheme: `• V_s = V_p × N_s / N_p = 230 × 100 / 500 (1)\n• = 46 V (1)` },
      { q: 'Write the equation for an ideal transformer relating power, voltage and current.', marks: 1, markScheme: `• V_p × I_p = V_s × I_s (1)` },
      { q: 'Explain why electricity is transmitted at very high voltage across the country.', marks: 5, markScheme: `• P = V × I so for fixed power, higher V means lower I (1)\n• Power loss in cables = I²R (1)\n• Lower I → far less heat dissipated in wires (1)\n• Transformers step up at power station and step down near homes (1)\n• Saves huge amounts of energy over the long transmission (1)` },
      { q: 'Draw an electric field pattern around a single positive charge, and between two opposite charges (+ and −).', marks: 4, requiresDiagram: true, markScheme: `• Radially outward arrows from +ve charge (1)\n• For two charges: curved field lines from + to − (1)\n• Lines closer together near charges (strong field) (1)\n• Clearly labelled +, − and direction of arrows (1)` },
      { q: 'State the rule for force between charges and for force between magnetic poles.', marks: 2, markScheme: `• Like charges repel, unlike charges attract (1)\n• Like magnetic poles repel, unlike attract (1)` },
      { q: 'Explain how a polythene rod becomes negatively charged when rubbed with a duster.', marks: 3, markScheme: `• Friction transfers electrons from the duster to the rod (1)\n• Rod gains electrons → becomes negatively charged (1)\n• Duster loses electrons → becomes positively charged (1)` },
      { q: 'Draw the magnetic field pattern around a bar magnet, clearly showing direction of field lines.', marks: 3, requiresDiagram: true, markScheme: `• Labelled N and S poles (1)\n• Curved field lines from N to S outside the magnet (1)\n• More densely spaced near the poles (1)` },
      { q: 'Describe how you could test whether a bar of steel is magnetic using a compass.', marks: 3, markScheme: `• Place a compass near one end of the steel bar (1)\n• If the needle deflects, the steel is producing a magnetic field (1)\n• Flip bar around — if deflection reverses, steel is a magnet, not just attracted to compass (1)` },
      { q: 'Compare the magnetism of iron and steel and explain why each is chosen for its typical use.', marks: 4, markScheme: `• Iron is a "soft" magnetic material — easily magnetised, loses magnetism when field removed (1)\n• Used in electromagnet cores / transformers (1)\n• Steel is "hard" — harder to magnetise but retains magnetism (1)\n• Used for permanent magnets / compass needles (1)` },
      { q: 'Describe how current in a solenoid creates a magnetic field similar to a bar magnet.', marks: 3, markScheme: `• Current in each coil creates a small circular field (1)\n• Fields from all coils combine — straight through the centre and around the outside (1)\n• Pattern resembles a bar magnet: one end acts as N, other as S (1)` },
      { q: 'Give three ways to increase the strength of an electromagnet.', marks: 3, markScheme: `• Add an iron core (1)\n• Increase the current (1)\n• Add more turns of wire (1)` },
      { q: 'State Fleming\'s left-hand rule and what each finger represents.', marks: 3, markScheme: `• First finger: magnetic Field direction (N→S) (1)\n• seCond finger: Current direction (+→−) (1)\n• thuMb: Motion/force of the wire (1)` },
      { q: 'State the equation F = B × I × L and name each quantity with units.', marks: 2, markScheme: `• F = force (N), B = magnetic flux density (T), I = current (A), L = length of wire in field (m) (2)` },
      { q: 'Describe, with a labelled diagram, how a simple dc motor works.', marks: 5, requiresDiagram: true, markScheme: `• Diagram: magnets N and S either side of a current-carrying coil, split-ring commutator, brushes, battery (2)\n• Current in the coil in a magnetic field experiences a force (motor effect) on each side (1)\n• Forces are opposite on each side, creating a couple → coil rotates (1)\n• Split-ring commutator reverses current in the coil every half turn so forces keep it turning the same way (1)` },
      { q: 'Describe what induced pd is, and give two ways to increase its size in a generator.', marks: 4, markScheme: `• Induced pd is the voltage produced when magnetic flux through a conductor changes (1)\n• Caused by relative motion between magnet and coil (or changing current in primary) (1)\n• Increase size by: faster rotation; stronger magnet; more turns of wire; larger coil area (any 2 for 2 marks)` },
      { q: 'A transformer is described as 95% efficient. Input is 1 000 W. State the output and where the missing 5% goes.', marks: 3, markScheme: `• Output = 95% × 1 000 = 950 W (1)\n• 50 W wasted (1)\n• Lost as heat in coils (resistance), eddy currents in iron core, and hysteresis (1)` },
    ]
  },

  /* ═════════════════════════════════════════════════════════ P4 Waves and Radioactivity */
  'P4': {
    name: 'Waves and Radioactivity',
    questions: [
      { q: 'Describe the difference between transverse and longitudinal waves.', marks: 3, markScheme: `• Transverse: oscillations are perpendicular to direction of energy transfer (e.g. light, water ripples) (1.5)\n• Longitudinal: oscillations are parallel (compressions/rarefactions) (e.g. sound) (1.5)` },
      { q: 'Write the wave equation with units.', marks: 2, markScheme: `• v = f × λ (1)\n• v (m/s), f (Hz), λ (m) (1)` },
      { q: 'Sketch a transverse wave and label wavelength, amplitude, crest, trough.', marks: 4, requiresDiagram: true, markScheme: `• Sinusoidal wave (1)\n• Crest and trough labelled (1)\n• Wavelength measured between corresponding points (1)\n• Amplitude labelled as max displacement from rest (1)` },
      { q: 'A sound wave has frequency 850 Hz and wavelength 0.40 m. Calculate its speed.', marks: 2, markScheme: `• v = f × λ = 850 × 0.40 (1)\n• = 340 m/s (1)` },
      { q: 'The speed of light is 3 × 10⁸ m/s. A yellow light has λ = 590 nm. Calculate frequency.', marks: 3, markScheme: `• Convert: 590 nm = 5.90 × 10⁻⁷ m (1)\n• f = v/λ = 3 × 10⁸ / 5.90 × 10⁻⁷ (1)\n• ≈ 5.1 × 10¹⁴ Hz (1)` },
      { q: 'State the law of reflection. Sketch a ray being reflected from a plane mirror to illustrate it.', marks: 3, requiresDiagram: true, markScheme: `• Angle of incidence = angle of reflection (both measured from the normal) (1)\n• Diagram: mirror surface with hatching, normal, incident + reflected ray with angles labelled i = r (2)` },
      { q: 'Explain the difference between specular and diffuse reflection.', marks: 3, markScheme: `• Specular — from smooth surface; parallel rays stay parallel; clear image (1.5)\n• Diffuse — from rough surface; rays scatter in many directions; no clear image (1.5)` },
      { q: 'A light ray enters a glass block. Describe what happens to its speed, wavelength and frequency.', marks: 3, markScheme: `• Speed decreases (denser medium) (1)\n• Wavelength decreases (since v = fλ and f is unchanged) (1)\n• Frequency stays the same (1)` },
      { q: 'Describe, with a labelled diagram, how to measure the refractive index of a glass block.', marks: 5, requiresDiagram: true, markScheme: `• Diagram: glass block on paper, incident ray, refracted ray, normals, angles i and r labelled (2)\n• Method: shine ray at angle i, mark entry/exit points, remove block, draw normals and rays (1)\n• Measure i and r with a protractor (1)\n• Plot sin i vs sin r — gradient = refractive index n (1)` },
      { q: 'Explain why light bends towards the normal when entering a denser medium.', marks: 3, markScheme: `• Denser medium → light travels slower (1)\n• When ray enters at angle, the side entering first slows down (1)\n• Causes wavefronts to change direction — bends towards the normal (1)` },
      { q: 'Describe diffraction of waves and state when it is most noticeable.', marks: 3, markScheme: `• Waves spread out when passing through a gap or around an obstacle (1)\n• Diffraction greatest when gap size ≈ wavelength (1)\n• For a much larger gap, little spreading is seen (1)` },
      { q: 'List the EM spectrum in order of increasing frequency.', marks: 2, markScheme: `• Radio → Microwaves → Infrared → Visible → Ultraviolet → X-rays → Gamma (2)` },
      { q: 'State one use and one hazard of microwaves.', marks: 2, markScheme: `• Use: cooking (absorbed by water in food), satellite/phone communications (1)\n• Hazard: can heat internal body tissues dangerously at high intensity (1)` },
      { q: 'State one use and one hazard of ultraviolet radiation.', marks: 2, markScheme: `• Use: sunbeds, sterilising equipment, fluorescent lights, security marks (1)\n• Hazard: sunburn, skin cancer, eye damage (1)` },
      { q: 'State one use and one hazard of X-rays.', marks: 2, markScheme: `• Use: medical imaging of bones, airport security, industrial inspection (1)\n• Hazard: ionising — causes DNA damage / cancer if dose too high (1)` },
      { q: 'Explain why UV, X-rays and gamma rays are all dangerous but visible light is not.', marks: 3, markScheme: `• Higher frequency = higher energy per photon (1)\n• UV, X, γ have enough energy to ionise atoms — knock electrons out (1)\n• Damages DNA, causes mutations/cancer; visible light photons cannot ionise (1)` },
      { q: 'Explain the working principle of ultrasound imaging.', marks: 4, markScheme: `• Pulses of ultrasound are sent into the body (1)\n• Partial reflection at each boundary between tissues of different density (1)\n• Time of return measured; distance = v × t / 2 (1)\n• Echoes are combined to build a 2-D image (1)` },
      { q: 'An ultrasound pulse returns from a foetal heart in 70 μs. Assuming v = 1 500 m/s in tissue, find the depth.', marks: 3, markScheme: `• Total path = v × t = 1 500 × 70 × 10⁻⁶ (1)\n• = 0.105 m (1)\n• Depth = half = 0.0525 m ≈ 5.3 cm (1)` },
      { q: 'State the range of human hearing.', marks: 1, markScheme: `• Approximately 20 Hz to 20 000 Hz (20 kHz) (1)` },
      { q: 'State three particles present in atoms and their relative charges.', marks: 3, markScheme: `• Proton: +1 (1)\n• Neutron: 0 (1)\n• Electron: −1 (1)` },
      { q: 'Explain what is meant by isotopes of an element.', marks: 2, markScheme: `• Same number of protons (same element) (1)\n• Different numbers of neutrons (different mass numbers) (1)` },
      { q: 'Describe Rutherford\'s gold-foil experiment and the conclusions he drew.', marks: 5, markScheme: `• α-particles fired at thin gold foil (1)\n• Most passed straight through (most of atom is empty space) (1)\n• Some deflected through large angles (positive charge concentrated) (1)\n• A very few bounced back (1)\n• Conclusion: atoms have a small, dense, positively charged nucleus containing most of the mass (1)` },
      { q: 'State the three main types of nuclear radiation and their particle nature.', marks: 3, markScheme: `• Alpha — helium nucleus (2 p + 2 n) (1)\n• Beta⁻ — high-speed electron from the nucleus (1)\n• Gamma — high-energy EM wave (1)` },
      { q: 'Draw a table comparing α, β and γ for charge, penetration, ionising power, stopped by.', marks: 4, markScheme: `• α: +2, few cm in air, very ionising, stopped by paper/skin (1)\n• β: −1, ~1 m in air, medium ionising, stopped by few mm aluminium (1)\n• γ: 0, hundreds of m, low ionising, need thick lead/concrete (1)\n• Properly formatted table (1)` },
      { q: 'Complete: ²²⁶₈₈Ra → ? + ⁴₂He. Identify the daughter.', marks: 2, markScheme: `• A = 226 − 4 = 222; Z = 88 − 2 = 86 (1)\n• Daughter: ²²²₈₆Rn (radon-222) (1)` },
      { q: 'Complete: ¹⁴₆C → ? + β⁻.', marks: 2, markScheme: `• β⁻ adds 1 to Z, A unchanged (1)\n• Daughter: ¹⁴₇N (1)` },
      { q: 'Define half-life.', marks: 2, markScheme: `• Average time for the number of undecayed nuclei (or activity) of a radioactive sample to halve (1)\n• Constant for a given isotope (1)` },
      { q: 'A source has activity 1 600 Bq and half-life 15 minutes. Calculate activity after 1 hour.', marks: 3, markScheme: `• 1 hour = 4 half-lives (1)\n• 1 600 → 800 → 400 → 200 → 100 Bq (1)\n• Final = 100 Bq (1)` },
      { q: 'A sample has activity dropping from 640 Bq to 80 Bq in 45 min. Find the half-life.', marks: 3, markScheme: `• 640 → 320 → 160 → 80 — 3 half-lives (1)\n• 3 t½ = 45 min (1)\n• t½ = 15 min (1)` },
      { q: 'Define the units becquerel (Bq) and sievert (Sv).', marks: 2, markScheme: `• Bq: unit of activity — 1 decay per second (1)\n• Sv: unit of radiation dose equivalent to a person (1)` },
      { q: 'Explain the difference between irradiation and contamination.', marks: 4, markScheme: `• Irradiation: object exposed to external radiation — danger stops when source removed (1)\n• Contamination: radioactive material on/inside the object or body (1)\n• Contamination is more persistent — continues radiating until decontaminated (1)\n• Different protection: irradiation → distance + shielding + time; contamination → gloves, masks, clean clothing, decontamination (1)` },
      { q: 'Why are γ emitters with short half-lives used as medical tracers rather than α emitters?', marks: 4, markScheme: `• γ penetrates out of the body to be detected externally (1)\n• α would be stopped within tissues and not detected (1)\n• α also ionises heavily inside the body — very damaging to cells (1)\n• Short half-life means activity decays quickly after scan, reducing total dose to patient (1)` },
      { q: 'Describe the sources of background radiation in the UK and the approximate share of each.', marks: 4, markScheme: `• Radon gas from rocks ~50% (1)\n• Medical scans ~14% (1)\n• Gamma rays from rocks/soil ~14%; cosmic rays ~10%; food/water ~12% (1)\n• Very small fraction (<1%) from nuclear industry / weapons fallout (1)` },
      { q: 'Explain why a worker handling α sources might be unharmed externally but at serious risk if a source is swallowed.', marks: 3, markScheme: `• External α is stopped by skin (or dead skin layer) (1)\n• Inside the body, α hits living cells directly (1)\n• Its high ionising power causes severe cellular damage in a small region (1)` },
      { q: 'Describe the process of nuclear fission.', marks: 4, markScheme: `• A slow neutron is absorbed by a fissile nucleus, e.g. U-235 (1)\n• The nucleus becomes unstable and splits into two smaller "daughter" nuclei (1)\n• Plus a few (usually 2–3) fast neutrons (1)\n• A large amount of energy is released (mass → energy) — these neutrons can trigger further fissions (chain reaction) (1)` },
      { q: 'Describe the process of nuclear fusion and state where it occurs naturally.', marks: 4, markScheme: `• Two light nuclei (isotopes of H) join to form a heavier nucleus (He) (1)\n• Needs very high temperature and pressure (1)\n• Releases large energy because mass decreases (E = mc²) (1)\n• Powers stars, including the Sun (1)` },
      { q: 'Compare advantages and disadvantages of fission and fusion for producing electricity on Earth.', marks: 6, markScheme: `• Fission: available now, high energy density, reliable (1)\n• Fission: long-lived radioactive waste, risk of meltdown (1)\n• Fusion: abundant fuel (deuterium), produces helium (stable), no long-lived waste (1)\n• Fusion: conditions extreme, still experimental, no net energy gain at commercial scale yet (1)\n• Both produce enormous energy per unit fuel; both low CO₂ (1)\n• Conclusion: fission used today, fusion is the potential future of low-carbon power (1)` },
      { q: 'State why it is safer to store spent nuclear fuel underwater.', marks: 3, markScheme: `• Water absorbs the radiation (1)\n• Water also removes heat from the fuel (still generating heat from short-half-life products) (1)\n• Prevents overheating and provides shielding for workers (1)` },
      { q: 'Describe, with a labelled diagram, the refraction of a light ray going from air into a semicircular glass block along the flat side and entering normally on the curved side.', marks: 4, requiresDiagram: true, markScheme: `• Diagram: semicircular block; ray enters on curved side (at centre = no bending as perpendicular to curve); refracts at flat air-glass boundary (2)\n• Labels: air, glass, normal, incident ray, refracted ray, angles (1)\n• Explanation of why no bending at curved face and why it bends at flat face (1)` },
      { q: 'Describe how Rutherford\'s atomic model differs from the plum-pudding model.', marks: 4, markScheme: `• Plum pudding: uniform positive sphere with electrons embedded (1)\n• Rutherford: most of mass and all positive charge in tiny central nucleus (1)\n• Atom is mostly empty space in Rutherford\'s model (1)\n• Electrons orbit nucleus at a distance, not embedded in the positive matter (1)` },
    ]
  },

  /* ═════════════════════════════════════════════════════════ P5 Energy */
  'P5': {
    name: 'Energy',
    questions: [
      { q: 'State the principle of conservation of energy.', marks: 1, markScheme: `• Energy cannot be created or destroyed, only transferred between stores (1)` },
      { q: 'List five examples of energy stores.', marks: 5, markScheme: `• Kinetic, gravitational potential, elastic potential, thermal/internal, chemical, magnetic, electrostatic, nuclear (1 each up to 5)` },
      { q: 'Give one example for each of the four pathways: mechanical, electrical, by heating, by radiation.', marks: 4, markScheme: `• Mechanical: lifting a box / pushing a cart (1)\n• Electrical: current doing work in an appliance (1)\n• By heating: hot water heating a pan (1)\n• Radiation: sunlight warming a surface / IR from a heater (1)` },
      { q: 'State the equation for kinetic energy and identify each term.', marks: 2, markScheme: `• E_k = ½ × m × v² (1)\n• E_k (J), m (kg), v (m/s) (1)` },
      { q: 'Calculate the KE of a 0.2 kg tennis ball travelling at 30 m/s.', marks: 2, markScheme: `• E_k = ½ × 0.2 × 30² (1)\n• = 90 J (1)` },
      { q: 'Explain why doubling the speed of a car quadruples its KE.', marks: 2, markScheme: `• E_k ∝ v² (1)\n• Doubling v gives 2² = 4× E_k (1)` },
      { q: 'State the equation for gravitational potential energy.', marks: 1, markScheme: `• E_p = m × g × h (1)` },
      { q: 'A 50 kg skater sits on top of a ramp 3 m high. Calculate the GPE (g = 9.8).', marks: 2, markScheme: `• E_p = 50 × 9.8 × 3 (1)\n• = 1 470 J (1)` },
      { q: 'State the equation for the elastic potential energy of a spring.', marks: 1, markScheme: `• E_e = ½ × k × e² (1)` },
      { q: 'A spring with constant 80 N/m is stretched by 0.25 m. Calculate the stored elastic PE.', marks: 2, markScheme: `• E = ½ × 80 × 0.25² (1)\n• = 2.5 J (1)` },
      { q: 'Write the equation for work done and explain how 1 J relates to force and distance.', marks: 2, markScheme: `• W = F × d (1)\n• 1 J = 1 N × 1 m of work (1)` },
      { q: 'Calculate the work done lifting a 5 kg bag 1.2 m (g = 9.8).', marks: 2, markScheme: `• W = mgh = 5 × 9.8 × 1.2 (1)\n• = 58.8 J (1)` },
      { q: 'State the equation for power and its unit.', marks: 2, markScheme: `• P = E / t or P = W / t (1)\n• Watt (W) = J/s (1)` },
      { q: 'A motor raises a 200 N load 15 m in 10 s. Calculate the useful output power.', marks: 3, markScheme: `• W = F × d = 200 × 15 = 3 000 J (1)\n• P = W/t = 3 000/10 (1)\n• = 300 W (1)` },
      { q: 'Define efficiency of a device and state the equation.', marks: 2, markScheme: `• Useful output ÷ total input, expressed as fraction or % (1)\n• η = E_useful / E_total × 100% (1)` },
      { q: 'A lamp uses 90 W and transfers 5 W as light. Find its efficiency.', marks: 2, markScheme: `• η = 5/90 × 100% (1)\n• ≈ 5.6% (1)` },
      { q: 'Draw a Sankey diagram for a 100 J input, 20 J useful light, 80 J wasted heat.', marks: 3, requiresDiagram: true, markScheme: `• Single arrow input labelled 100 J (1)\n• Two branches with widths proportional to 20 J (useful) and 80 J (wasted) (1)\n• Each branch labelled and arrows in correct direction (1)` },
      { q: 'Explain why a pendulum gradually stops even though energy is "conserved".', marks: 3, markScheme: `• Total energy is conserved — KE ↔ GPE (1)\n• Air resistance and pivot friction transfer some mechanical energy to thermal (1)\n• Mechanical energy decreases each swing → amplitude falls → pendulum stops (1)` },
      { q: 'A 2 kg ball falls 5 m from rest. Calculate its speed just before hitting the ground (ignore air resistance, g = 9.8).', marks: 4, markScheme: `• GPE lost = mgh = 2 × 9.8 × 5 = 98 J (1)\n• All → KE: ½ × 2 × v² = 98 (1)\n• v² = 98 (1)\n• v = 9.9 m/s (1)` },
      { q: 'State three factors that reduce the energy wasted by a moving car.', marks: 3, markScheme: `• Aerodynamic shape (reduces air resistance) (1)\n• Lubrication and well-maintained bearings (reduce friction) (1)\n• Regenerative braking (recovers some KE into battery), low-rolling-resistance tyres (1)` },
      { q: 'Explain how loft insulation reduces heat loss from a house.', marks: 3, markScheme: `• Insulation contains trapped air pockets (1)\n• Air has a very low thermal conductivity → slows conduction through the roof (1)\n• Less heat is lost from the upper surface per unit time → lower energy bills (1)` },
      { q: 'Explain how double glazing reduces heat loss through windows.', marks: 3, markScheme: `• Two panes of glass with a thin gas/air gap between (1)\n• Air or argon gas conducts heat very slowly (1)\n• Reduces conduction (and some convection) through the window (1)` },
      { q: 'State three renewable and three non-renewable energy resources.', marks: 3, markScheme: `• Renewable: solar, wind, hydro, tidal, wave, geothermal, biofuel (any 3 for 1.5)\n• Non-renewable: coal, oil, natural gas, nuclear (any 3 for 1.5)` },
      { q: 'Evaluate advantages and disadvantages of wind power.', marks: 4, markScheme: `• Advantages: renewable, no CO₂ at generation, free "fuel" (wind) (2)\n• Disadvantages: only generates when wind blows (intermittent); visual impact; possible bird strikes (2)` },
      { q: 'Evaluate advantages and disadvantages of nuclear power.', marks: 4, markScheme: `• Advantages: very high energy density, low direct CO₂, reliable base-load (2)\n• Disadvantages: long-lived radioactive waste, expensive to build, accident risk (2)` },
      { q: 'Evaluate advantages and disadvantages of fossil-fuel power stations.', marks: 4, markScheme: `• Advantages: reliable, existing infrastructure, high power output on demand (2)\n• Disadvantages: CO₂ emissions → climate change; pollutants (SO₂, NOₓ, particulates); finite reserves (2)` },
      { q: 'Explain what is meant by base-load and variable renewable generation.', marks: 3, markScheme: `• Base-load: provides a steady output 24/7 (e.g. nuclear, some gas, biomass) (1)\n• Variable renewables (wind, solar) produce electricity only when conditions allow (1)\n• Grid mixes both to match demand (1)` },
      { q: 'Describe how pumped-storage hydroelectric works and why it is useful to the grid.', marks: 4, markScheme: `• Off-peak surplus electricity pumps water uphill into a reservoir (1)\n• GPE is stored (m g h) (1)\n• At peak demand, water flows down through turbines, generating electricity (1)\n• Fast response + large capacity → balances supply and demand (1)` },
      { q: 'Explain why the UK has been phasing out coal.', marks: 4, markScheme: `• Coal produces high CO₂ emissions → contributes to climate change (1)\n• It produces SO₂, NOₓ, particulates → acid rain and poor air quality (1)\n• Falling costs of wind and solar make coal less economic (1)\n• Net-zero target by 2050 requires low-carbon energy sources (1)` },
      { q: 'State Hooke\'s law and the equation linking force and extension.', marks: 2, markScheme: `• Force applied is directly proportional to extension (up to the limit of proportionality) (1)\n• F = k × e, where k is the spring constant (1)` },
      { q: 'A spring has a spring constant of 250 N/m. Calculate the force required for a 0.12 m extension.', marks: 2, markScheme: `• F = k × e = 250 × 0.12 (1)\n• = 30 N (1)` },
      { q: 'Draw a labelled force-extension graph for a spring up to and beyond the elastic limit.', marks: 4, requiresDiagram: true, markScheme: `• Axes: force (y) vs extension (x) labelled (1)\n• Straight line through origin initially (1)\n• Curve beyond the limit of proportionality (1)\n• Limit of proportionality and elastic limit labelled (1)` },
      { q: 'Describe how you could investigate the spring constant of a spring.', marks: 5, markScheme: `• Hang spring vertically from a clamp stand beside a ruler (1)\n• Measure natural length at no load (1)\n• Add known masses one at a time; measure extension at each (1)\n• Plot F (= mg) vs extension (1)\n• k = gradient of linear region (1)` },
      { q: 'Compare the advantages of a solar water heating panel and a photovoltaic (PV) panel.', marks: 4, markScheme: `• Solar thermal: simple, directly heats water; very high efficiency for heating (~60–80%) (2)\n• PV: produces electricity, versatile; lower efficiency (~20%) but more useful electrically (2)` },
      { q: 'A kettle uses 300 kJ to boil 1 kg of water from 20 °C to 100 °C. Ideally the energy needed (c = 4 200) is less — calculate that, then compute efficiency.', marks: 4, markScheme: `• Required = mcΔθ = 1 × 4 200 × 80 = 336 000 J = 336 kJ (1)\n• But only 300 kJ supplied — in reality kettle usually supplies MORE than 336 kJ to make up losses. Assuming here 300 kJ is supplied for 336 kJ required, recalc with sensible numbers.\nAlternative: A kettle uses 400 kJ to do 336 kJ useful heating. Efficiency = 336/400 × 100% = 84% (2)\n• Rest lost through walls, handle, steam (1)` },
      { q: 'Explain why LED bulbs are much more efficient than filament bulbs.', marks: 3, markScheme: `• Filament bulbs convert most electrical energy to heat (~5% to light) (1)\n• LEDs convert electrical directly to light via a semiconductor junction — less heat (1)\n• Efficiency can exceed 30–40% for LEDs, dramatically reducing wasted energy (1)` },
      { q: 'A crane has 70% efficiency, lifts a 1 200 kg load 15 m in 20 s (g = 10). Calculate input power.', marks: 4, markScheme: `• Useful work = mgh = 1 200 × 10 × 15 = 180 000 J (1)\n• Useful power out = 180 000 / 20 = 9 000 W (1)\n• Efficiency = useful/total → total = 9 000/0.70 (1)\n• ≈ 12 857 W ≈ 12.9 kW (1)` },
      { q: 'A car climbs a hill of height 25 m with 70% efficiency, starting at 20 m/s and stopping at top. Mass 1 200 kg (g = 10). Work done by the engine?', marks: 5, markScheme: `• KE lost = ½ × 1 200 × 20² = 240 000 J (this KE is lost — brakes/friction) (1)\n• GPE gained = 1 200 × 10 × 25 = 300 000 J (1)\n• Useful output = GPE gained = 300 000 J (1)\n• Engine work = 300 000 / 0.70 (1)\n• ≈ 428 571 J ≈ 429 kJ (1)` },
      { q: 'A pendulum bob is lifted 0.25 m and released. Assuming no friction, find its maximum speed at the bottom (g = 9.8).', marks: 3, markScheme: `• GPE = KE at bottom: mgh = ½mv² → v = √(2gh) (1)\n• v = √(2 × 9.8 × 0.25) = √4.9 (1)\n• = 2.21 m/s (1)` },
      { q: 'Describe, with a labelled Sankey diagram, the energy transfers in a car travelling at constant speed.', marks: 5, requiresDiagram: true, markScheme: `• Input arrow labelled chemical energy from fuel (100%) (1)\n• Output branches: KE maintained ~ 0 (no change at constant v) (1)\n• Major branch as heat (engine, friction, exhaust) (1)\n• Sound, air resistance (1)\n• All branches labelled with approximate fraction; widths proportional (1)` },
    ]
  },

  /* ═════════════════════════════════════════════════════════ P6 Global Challenges */
  'P6': {
    name: 'Global Challenges',
    questions: [
      { q: 'Describe electromagnetic induction.', marks: 3, markScheme: `• A changing magnetic field through a conductor (1)\n• Induces a potential difference (emf) (1)\n• If a circuit is complete, a current flows; effect is the basis of generators and transformers (1)` },
      { q: 'State two ways to induce a larger pd in a coil next to a magnet.', marks: 2, markScheme: `• Move magnet faster (faster change of flux) (1)\n• Use a stronger magnet / more turns on coil (any 1 for 1 mark)` },
      { q: 'Describe, with a labelled diagram, how a simple AC generator works.', marks: 5, requiresDiagram: true, markScheme: `• Diagram: rotating coil in a magnetic field, slip rings, brushes, load (2)\n• Coil rotates → magnetic flux through coil changes (1)\n• Induced emf alternates as the coil turns — each side of coil moves up then down (1)\n• Slip rings keep continuous output connection; output is AC (1)` },
      { q: 'Write the transformer voltage ratio equation and name each symbol.', marks: 2, markScheme: `• V_p / V_s = N_p / N_s (1)\n• V_p, V_s = primary/secondary pds; N_p, N_s = number of turns (1)` },
      { q: 'Transformer has 2 000 turns primary, 200 secondary, 230 V ac input. Calculate the output voltage and state whether step-up or step-down.', marks: 3, markScheme: `• V_s = 230 × 200 / 2 000 (1)\n• = 23 V (1)\n• Step-down (fewer turns on secondary) (1)` },
      { q: 'Assuming ideal (100% efficient): if the secondary current in the above transformer is 5 A, what is the primary current?', marks: 3, markScheme: `• V_p I_p = V_s I_s (1)\n• 230 × I_p = 23 × 5 → I_p = 115/230 (1)\n• = 0.5 A (1)` },
      { q: 'Explain why transformers do not work with direct current.', marks: 3, markScheme: `• DC produces a steady magnetic field in the primary coil (1)\n• Steady field → no change in flux (1)\n• Without changing flux, no emf is induced in the secondary (1)` },
      { q: 'State why real transformers are not 100% efficient.', marks: 3, markScheme: `• Resistance in coils dissipates heat (I²R losses) (1)\n• Eddy currents induced in iron core dissipate heat (reduced by laminating the core) (1)\n• Hysteresis losses — repeated magnetisation/demagnetisation of iron (1)` },
      { q: 'Explain why the National Grid uses extremely high voltages for transmission.', marks: 5, markScheme: `• P = V × I — higher V gives lower I for same power (1)\n• Power lost in cables = I²R (1)\n• Lower I → dramatically less heat dissipated in wires (1)\n• Step-up transformer used at power stations and step-down near homes (1)\n• Saves large amounts of energy over the long distance (1)` },
      { q: 'Name and place (in order from Sun) the eight planets.', marks: 2, markScheme: `• Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune (2 marks if all correct; 1 if mostly correct)` },
      { q: 'State the difference between a planet and a dwarf planet.', marks: 2, markScheme: `• Both orbit the Sun and are roughly spherical (1)\n• A planet has cleared its orbital path of debris; a dwarf planet (e.g. Pluto) has not (1)` },
      { q: 'Explain why a satellite needs gravity to stay in a stable orbit.', marks: 4, markScheme: `• Satellite moves tangentially at high speed (1)\n• Gravitational force pulls it towards the centre of the Earth (1)\n• This acts as the centripetal force, changing the direction of velocity (1)\n• Speed is constant but direction changes continuously — satellite orbits rather than flies away or falls in (1)` },
      { q: 'Explain why, at a fixed distance, only one specific orbital speed gives a stable circular orbit.', marks: 3, markScheme: `• Gravity provides the centripetal force required for circular motion (1)\n• Required force depends on v²/r (too fast → spirals out; too slow → falls in) (1)\n• Only one v matches the gravitational force at a given r (1)` },
      { q: 'Explain why geostationary satellites orbit in 24 hours and why they are useful.', marks: 4, markScheme: `• They orbit at a specific altitude (~36 000 km) where period = 24 hours (1)\n• Stay above the same point on the equator as Earth rotates (1)\n• Stationary relative to ground — fixed dish antenna can always point at them (1)\n• Used for TV broadcasting, communications (1)` },
      { q: 'Describe the stages in the life cycle of a Sun-like star (medium mass).', marks: 5, markScheme: `• Nebula (cloud of gas/dust) contracts under gravity (1)\n• Forms a protostar as density and temperature rise (1)\n• Main-sequence star when H-fusion begins in the core (1)\n• Red giant as H runs out, core contracts, outer layers expand and cool (1)\n• Outer layers drift off, leaving a white dwarf → cools over time (1)` },
      { q: 'Describe the stages in the life cycle of a massive star (more than about 8 solar masses).', marks: 5, markScheme: `• Nebula → protostar → main-sequence (hotter, blue) (1)\n• Red supergiant as core elements (up to iron) fuse (1)\n• Supernova explosion scatters heavy elements into space (1)\n• Depending on mass, remnant is a neutron star or a black hole (1)\n• Heavy elements (beyond iron) are created in supernovae — the source of elements like gold and uranium (1)` },
      { q: 'Explain what red-shift is and how it is evidence for an expanding universe.', marks: 4, markScheme: `• Observed wavelengths of light from distant galaxies are longer than measured in lab (1)\n• Galaxies are moving away → Doppler-like effect stretches wavelengths (1)\n• Further galaxies show greater red-shift — moving away faster (1)\n• Implication: space itself is expanding, carrying galaxies along with it → Big Bang theory (1)` },
      { q: 'State two pieces of evidence for the Big Bang (other than red-shift).', marks: 2, markScheme: `• Cosmic microwave background (CMB) — uniform microwave glow from all directions (1)\n• Observed abundance of light elements (hydrogen, helium) matches nucleosynthesis predictions (1)` },
      { q: 'Explain the meaning of the cosmic microwave background radiation.', marks: 3, markScheme: `• CMB is the cooled afterglow of the hot early universe (1)\n• Originally high-energy photons, now red-shifted to microwaves as space has expanded for ~13.8 Gyr (1)\n• Detected uniformly in all directions — consistent with Big Bang model (1)` },
      { q: 'Define "light-year" and give its approximate value in metres.', marks: 2, markScheme: `• Distance light travels in one year (1)\n• ≈ 9.5 × 10¹⁵ m (1)` },
      { q: 'State what is meant by dark matter.', marks: 2, markScheme: `• Matter that does not emit or absorb detectable light (1)\n• Its gravitational effect is needed to explain the observed motion of galaxies (1)` },
      { q: 'State what is meant by dark energy.', marks: 2, markScheme: `• A form of energy associated with empty space (1)\n• Causes the accelerating expansion of the universe (observed since 1998) (1)` },
      { q: 'Give one use of each of the following satellite types: GPS, weather, Hubble-like telescope.', marks: 3, markScheme: `• GPS: navigation, time synchronisation (1)\n• Weather: monitoring cloud movements, climate data (1)\n• Telescope (e.g. Hubble, JWST): astronomy beyond atmospheric distortion / absorption (1)` },
      { q: 'Explain why space telescopes are used to image in the UV and far-IR.', marks: 3, markScheme: `• UV is mostly absorbed by the atmosphere\'s ozone layer (1)\n• Far-IR is mostly absorbed by water vapour and CO₂ (1)\n• Placing telescope above the atmosphere avoids these losses and gives much sharper images (1)` },
      { q: 'Explain why the Earth\'s atmosphere is described as having "windows" for certain EM wavelengths.', marks: 3, markScheme: `• Atmosphere is transparent to visible light and most radio waves (1)\n• Opaque to much of UV, IR, and microwave (1)\n• Ground-based astronomy can only observe these "windows"; the rest needs satellites (1)` },
      { q: 'Explain the greenhouse effect at a simple level.', marks: 4, markScheme: `• Short-wavelength radiation from the Sun passes through the atmosphere and warms the Earth (1)\n• Earth re-radiates energy as longer-wavelength infrared (1)\n• Greenhouse gases (CO₂, CH₄, water vapour) absorb this IR and re-emit it in all directions (1)\n• This traps heat near the surface, raising the average temperature (1)` },
      { q: 'Describe how human activity has increased atmospheric CO₂ and the expected effect.', marks: 3, markScheme: `• Burning fossil fuels releases CO₂ (1)\n• Deforestation reduces CO₂ absorption by plants (1)\n• More CO₂ → stronger greenhouse effect → global warming, climate change (melting ice, rising sea levels, more extreme weather) (1)` },
      { q: 'State two ways science/technology are helping reduce CO₂ emissions.', marks: 2, markScheme: `• Switch to renewable electricity (wind, solar), grid storage (1)\n• Electric vehicles / heat pumps replacing fossil-fuel heating and transport (1)` },
      { q: 'State what is meant by "renewable" energy resource.', marks: 2, markScheme: `• A resource that is replenished at least as fast as it is used (1)\n• Will not run out on a human timescale (1)` },
      { q: 'Compare the reliability of solar, wind, and tidal power.', marks: 3, markScheme: `• Solar: varies with time of day and weather (intermittent) (1)\n• Wind: varies with weather (intermittent but different pattern from solar) (1)\n• Tidal: extremely predictable (driven by Moon and Sun orbital mechanics) (1)` },
      { q: 'Explain why hydrogen is proposed as a "clean" fuel, and state ONE issue with it.', marks: 3, markScheme: `• Burning H₂ produces only water (no CO₂) (1)\n• Can be generated from water using renewable electricity (green hydrogen) (1)\n• Issue: most hydrogen today is made from natural gas (grey hydrogen) — still emits CO₂. Also difficult to store/transport safely (1)` },
      { q: 'State what is meant by "net zero" CO₂ emissions and describe ONE way it could be achieved.', marks: 3, markScheme: `• Net zero means that any CO₂ emitted is balanced by equal CO₂ removed from the atmosphere (1)\n• Eliminate fossil-fuel electricity, transport, heating (1)\n• Use renewables / nuclear, plus carbon capture and reforestation to offset remaining emissions (1)` },
      { q: 'Describe, in outline, how electricity is generated in a wind turbine.', marks: 4, markScheme: `• Wind blows across aerofoil-shaped blades, making them rotate (1)\n• Rotation drives a shaft that turns a generator (1)\n• Rotating coil in magnetic field induces emf (electromagnetic induction) (1)\n• AC current generated; transformed and fed into grid (1)` },
      { q: 'Describe, in outline, how electricity is generated in a coal-fired power station.', marks: 5, markScheme: `• Coal is burned in a furnace, releasing thermal energy (1)\n• Water is heated in a boiler to produce high-pressure steam (1)\n• Steam drives turbines that rotate (1)\n• Turbines turn a generator → induced emf (1)\n• AC transformer steps up voltage for transmission; CO₂ is released from combustion (1)` },
      { q: 'Describe how a pumped-storage hydro-station works and why it is valuable to the grid.', marks: 5, markScheme: `• Two reservoirs at different heights (1)\n• During surplus (off-peak), electricity pumps water uphill — storing GPE (1)\n• During peak demand, water flows down through turbines, generating electricity (1)\n• Provides very fast response (seconds to minutes) (1)\n• Balances intermittent renewables and demand peaks (1)` },
      { q: 'Explain why the universe contains a mix of elements and why most of this came from stars.', marks: 4, markScheme: `• Big Bang produced mostly hydrogen and helium (1)\n• Heavier elements (up to iron) are produced in stellar fusion over a star\'s lifetime (1)\n• Elements heavier than iron are forged in supernovae explosions of massive stars (1)\n• These elements are scattered into space when stars shed outer layers, later forming new stars and planets (including Earth) (1)` },
      { q: 'Explain why an absolute zero (0 K) exists and what it represents.', marks: 3, markScheme: `• At absolute zero, particles have the minimum possible kinetic energy (1)\n• 0 K = −273 °C (1)\n• A gas at 0 K would, by extrapolation, occupy zero volume and exert zero pressure (not achievable in practice) (1)` },
      { q: 'Describe how astronomers measure the distance to nearby stars using parallax.', marks: 4, markScheme: `• Earth moves around the Sun, changing our viewing angle by up to 2 AU diameter (1)\n• A nearby star appears to shift against distant background stars when Earth is on opposite sides (1)\n• Measure the angle of shift; use trigonometry → d = 1/p (in parsecs if p is in arcseconds) (1)\n• Works only for nearby stars (few hundred pc); further stars need other methods (1)` },
      { q: 'Briefly explain the importance of the James Webb Space Telescope for modern astronomy.', marks: 4, markScheme: `• Large infrared space telescope at L2 (~1.5 million km from Earth) (1)\n• Can see light from the earliest galaxies, red-shifted into infrared (1)\n• Cooled environment avoids warm Earth/Sun thermal interference (1)\n• Insights into star/planet formation, atmospheres of exoplanets — key to frontier astrophysics (1)` },
      { q: 'Discuss whether the UK should rely more on nuclear or more on renewables for its electricity future. Give your overall conclusion.', marks: 6, markScheme: `• Nuclear: high reliable output, low CO₂, needed as base-load; but expensive to build, radioactive waste problem (2)\n• Renewables: free "fuel", low environmental impact once built; intermittent (solar/wind) needing storage (2)\n• Balance: renewables + storage + smart grid can approach 24/7 coverage; nuclear provides stable supply especially for peak winter demand (1)\n• Conclusion (any reasoned stance): most cost-effective low-carbon future is LIKELY a mix of both renewables and nuclear, with renewables growing fastest as costs fall; pure reliance on one brings either security or cost risks (1)` },
    ]
  },

};

if (typeof module !== 'undefined' && module.exports) module.exports = PHYSICS_OCR_A_GCSE_PRACTICE;
